    return (
        <div className="container">
            <Header/>
        <div className='row rowstyle'>
            <div className='col-6 comp-item'>
                <h1>Sony Music Group</h1>
            </div>
            <div className='col-6 comp-item'>
                <h1>Empire Music Group</h1>
            </div>
        </div>
        <Footer/>
        </div>

    )
}
